import{_ as a,o as l,c as e,a2 as o}from"./chunks/framework.DS_HIvHc.js";const p=JSON.parse('{"title":"온보딩 체크리스트","description":"","frontmatter":{},"headers":[],"relativePath":"guide/checklist.md","filePath":"guide/checklist.md","lastUpdated":1773710852000}'),i={name:"guide/checklist.md"};function d(r,t,s,c,u,n){return l(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="온보딩-체크리스트" tabindex="-1">온보딩 체크리스트 <a class="header-anchor" href="#온보딩-체크리스트" aria-label="Permalink to &quot;온보딩 체크리스트&quot;">​</a></h1><blockquote><p>Claude Desktop Cowork를 처음 시작하는 분을 위한 단계별 체크리스트입니다. 하나씩 체크하며 따라가 보세요.</p></blockquote><div class="tip custom-block"><p class="custom-block-title">활용법</p><p>이 페이지를 북마크하거나 인쇄해서 책상에 두세요. 항목을 하나씩 완료할 때마다 체크하면 빠짐없이 온보딩할 수 있습니다.</p></div><h2 id="day-1-설치-기본-설정" tabindex="-1">Day 1: 설치 &amp; 기본 설정 <a class="header-anchor" href="#day-1-설치-기본-설정" aria-label="Permalink to &quot;Day 1: 설치 &amp; 기본 설정&quot;">​</a></h2><ul><li>[ ] Claude Desktop 다운로드 &amp; 설치 (<a href="https://claude.ai/download" target="_blank" rel="noreferrer">claude.ai/download</a>)</li><li>[ ] 계정 로그인 (회사 계정 or 개인 계정)</li><li>[ ] Cowork 모드 활성화</li><li>[ ] 작업 폴더 선택 &amp; 파일 접근 허용</li><li>[ ] 언어 설정 확인 (한국어)</li><li>[ ] 첫 번째 대화 시도 (&quot;안녕, 나는 [이름]이고 [부서]에서 일해&quot;)</li></ul><div class="info custom-block"><p class="custom-block-title">첫 대화가 중요합니다</p><p>자기소개를 하면 Claude가 맥락을 기억하고, 이후 대화에서 더 적절한 답변을 줍니다. 부서, 역할, 주로 하는 업무를 알려주세요.</p></div><h2 id="day-1-첫-번째-실전-활용" tabindex="-1">Day 1: 첫 번째 실전 활용 <a class="header-anchor" href="#day-1-첫-번째-실전-활용" aria-label="Permalink to &quot;Day 1: 첫 번째 실전 활용&quot;">​</a></h2><ul><li>[ ] 이메일 하나 작성 요청해보기</li><li>[ ] 파일 하나 읽기 &amp; 요약 요청해보기</li><li>[ ] 수정 요청해보기 (&quot;톤을 바꿔줘&quot;, &quot;더 짧게&quot;)</li><li>[ ] 결과물 저장 or 복사해서 실제 업무에 사용</li></ul><div class="tip custom-block"><p class="custom-block-title">핵심 포인트</p><p>처음부터 완벽한 결과를 기대하지 않아도 됩니다. <strong>수정 요청</strong>이 Cowork의 핵심입니다. &quot;좀 더 공손하게&quot;, &quot;숫자를 표로 정리해줘&quot;처럼 자유롭게 요청하세요.</p></div><h2 id="day-2-3-익숙해지기" tabindex="-1">Day 2-3: 익숙해지기 <a class="header-anchor" href="#day-2-3-익숙해지기" aria-label="Permalink to &quot;Day 2-3: 익숙해지기&quot;">​</a></h2><ul><li>[ ] Custom Instructions 설정 (팀 규칙, 선호 양식 등)</li><li>[ ] 프로젝트 하나 만들어보기</li><li>[ ] 데이터 파일(엑셀/CSV) 분석 요청해보기</li><li>[ ] 긴 문서 요약 요청해보기</li><li>[ ] 기초 테스트 시나리오 4개 완료</li></ul><div class="info custom-block"><p class="custom-block-title">Custom Instructions란?</p><p>매번 같은 지시를 반복하지 않도록, 미리 규칙을 저장해두는 기능입니다. 예를 들어 &quot;항상 존댓말로 답변해줘&quot;, &quot;보고서는 우리 팀 양식으로 써줘&quot; 같은 설정을 해두면 매 대화에 자동으로 적용됩니다.</p></div><h2 id="week-1-업무에-정착" tabindex="-1">Week 1: 업무에 정착 <a class="header-anchor" href="#week-1-업무에-정착" aria-label="Permalink to &quot;Week 1: 업무에 정착&quot;">​</a></h2><ul><li>[ ] 매일 반복하는 업무 1개를 Claude로 처리</li><li>[ ] 심화 테스트 시나리오 도전</li><li>[ ] 프롬프트 치트시트 즐겨찾기</li><li>[ ] 동료에게 유용한 프롬프트 하나 공유</li><li>[ ] &quot;자주 하는 실수&quot; 페이지 읽기</li></ul><div class="tip custom-block"><p class="custom-block-title">동료와 공유하세요</p><p>좋은 프롬프트를 발견하면 팀 채팅방이나 메일로 공유해보세요. 팀 전체의 생산성이 올라갑니다.</p></div><h2 id="week-2-파워-유저" tabindex="-1">Week 2+: 파워 유저 <a class="header-anchor" href="#week-2-파워-유저" aria-label="Permalink to &quot;Week 2+: 파워 유저&quot;">​</a></h2><ul><li>[ ] MCP 연동 탐색 (외부 도구와 Claude 연결)</li><li>[ ] 팀 프로젝트 활용 (팀원들과 같은 프로젝트에서 협업)</li><li>[ ] 나만의 프롬프트 템플릿 3개 이상 만들기</li><li>[ ] 월간 업무에 Claude 활용 루틴 정착</li></ul><hr><h2 id="나의-온보딩-진행률" tabindex="-1">나의 온보딩 진행률 <a class="header-anchor" href="#나의-온보딩-진행률" aria-label="Permalink to &quot;나의 온보딩 진행률&quot;">​</a></h2><table tabindex="0"><thead><tr><th>단계</th><th>항목 수</th><th>완료</th></tr></thead><tbody><tr><td>Day 1: 설치 &amp; 기본 설정</td><td>6개</td><td>__ / 6</td></tr><tr><td>Day 1: 첫 번째 실전 활용</td><td>4개</td><td>__ / 4</td></tr><tr><td>Day 2-3: 익숙해지기</td><td>5개</td><td>__ / 5</td></tr><tr><td>Week 1: 업무에 정착</td><td>5개</td><td>__ / 5</td></tr><tr><td>Week 2+: 파워 유저</td><td>4개</td><td>__ / 4</td></tr><tr><td><strong>합계</strong></td><td><strong>24개</strong></td><td><strong>__ / 24</strong></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">체크를 많이 할수록 업무 효율이 올라갑니다!</p><p>모든 항목을 완료하면 Claude Desktop Cowork를 자유자재로 활용할 수 있는 <strong>파워 유저</strong>가 됩니다. 서두르지 말고, 2주에 걸쳐 하나씩 완료해보세요.</p></div>',21)])])}const k=a(i,[["render",d]]);export{p as __pageData,k as default};
